mods.css:
:root{
  --accent:#ff4d6d !important;
  --highlight:#ffd93d !important;
}

body{
  background:
    radial-gradient(circle at top left,#ff0080 0%,transparent 25%),
    radial-gradient(circle at top right,#7928ca 0%,transparent 25%),
    radial-gradient(circle at bottom left,#00c6ff 0%,transparent 25%),
    radial-gradient(circle at bottom right,#00ff99 0%,transparent 25%),
    #05060a !important;
  background-attachment: fixed;
}

.header,
.settings-menu,
.filter-panel,
.preview-content,
.modal-box{
  background:rgba(15,15,20,0.82)!important;
  backdrop-filter:blur(18px)!important;
  border:1px solid rgba(255,255,255,0.08)!important;
}

.item-row,
.link-card,
.group-container{
  background:linear-gradient(
    135deg,
    rgba(255,0,128,0.15),
    rgba(0,198,255,0.15),
    rgba(0,255,153,0.15)
  ) !important;

  border:1px solid rgba(255,255,255,0.08)!important;
  backdrop-filter:blur(10px)!important;

  transition:0.25s ease;
}

.item-row:hover,
.link-card:hover{
  transform:translateY(-3px) scale(1.01);
  box-shadow:
    0 0 20px rgba(255,0,128,0.35),
    0 0 40px rgba(0,198,255,0.25);
}

.btn-primary,
.btn-filter,
.btn-settings{
  background:linear-gradient(
    90deg,
    #ff0080,
    #7928ca,
    #00c6ff,
    #00ff99
  ) !important;

  border:none!important;
  color:white!important;
  font-weight:700!important;
}

.link-title{
  background:linear-gradient(
    90deg,
    #ff4d6d,
    #ffd93d,
    #00c6ff,
    #00ff99
  );

  -webkit-background-clip:text;
  -webkit-text-fill-color:transparent;

  font-weight:800!important;
}

.slider-btn,
.btn-icon{
  background:rgba(255,255,255,0.08)!important;
  border-radius:12px!important;
}

::-webkit-scrollbar{
  width:10px;
  height:10px;
}

::-webkit-scrollbar-thumb{
  background:linear-gradient(
    180deg,
    #ff0080,
    #7928ca,
    #00c6ff
  );
  border-radius:999px;
}
